       // taking ext.
       if (F.ScaledReg) {
-        const SCEV *NewScaledReg = SE.getAnyExtendExpr(F.ScaledReg, SrcTy);
+        const SCEV *NewScaledReg =
+            getAnyExtendConsideringPostIncUses(LU, F.ScaledReg, SrcTy, SE);
         if (NewScaledReg->isZero())
          continue;
         F.ScaledReg = NewScaledReg;
       }
