       for (const SCEV *&BaseReg : F.BaseRegs) {
-        const SCEV *NewBaseReg = SE.getAnyExtendExpr(BaseReg, SrcTy);
+        const SCEV *NewBaseReg =
+            getAnyExtendConsideringPostIncUses(LU, BaseReg, SrcTy, SE);
         if (NewBaseReg->isZero()) {
